// --- Cosmos DB context demonstrating EF Core 9 breaking change fixes ---

class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();
    public DbSet<DiscountedProduct> DiscountedProducts => Set<DiscountedProduct>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb");
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // BREAKING CHANGE 1: EF Core 9 renamed the discriminator property
        // from "Discriminator" to "$type". Existing documents still use
        // "Discriminator", so we must explicitly configure the old name
        // to avoid data-loss / read failures.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator")
            .HasValue<Product>("Product")
            .HasValue<DiscountedProduct>("DiscountedProduct");

        modelBuilder.Entity<Product>().ToContainer("Products");
        modelBuilder.Entity<Product>().HasPartitionKey(p => p.Category);
    }
}

class Product
{
    public string Id { get; set; } = default!;
    public string Name { get; set; } = default!;
    public string Category { get; set; } = default!;
}

class DiscountedProduct : Product
{
    public decimal Discount { get; set; }
}

// BREAKING CHANGE 2: EF Core 9 Cosmos provider removed synchronous I/O
// support. All queries must use async methods (ToListAsync, FirstAsync, etc.).
// Synchronous calls like .ToList() now throw InvalidOperationException.

class CosmosQueryService
{
    private readonly CosmosDbContext _db;
    public CosmosQueryService(CosmosDbContext db) => _db = db;

    // WRONG (EF Core 8 allowed this):
    // public List<Product> GetAll() => _db.Products.ToList();

    // FIXED – use async:
    public async Task<List<Product>> GetAllAsync()
        => await _db.Products.ToListAsync();

    public async Task<Product?> GetByIdAsync(string id)
        => await _db.Products.FirstOrDefaultAsync(p => p.Id == id);
}

